79: public class SaslChannelBuilder implements ChannelBuilder, ListenerReconfigurable {
80:     static final String GSS_NATIVE_PROP = "sun.security.jgss.native";
81: 
82:     private final SecurityProtocol securityProtocol;
83:     private final ListenerName listenerName;
84:     private final boolean isInterBrokerListener;
85:     private final String clientSaslMechanism;
86:     private final ConnectionMode connectionMode;
87:     private final Map<String, JaasContext> jaasContexts;
88:     private final CredentialCache credentialCache;
89:     private final DelegationTokenCache tokenCache;
90:     private final Map<String, LoginManager> loginManagers;
91:     private final Map<String, Subject> subjects;
92:     private final Function<Short, ApiVersionsResponse> apiVersionSupplier;
93:     private final String sslClientAuthOverride;
94:     private final Map<String, AuthenticateCallbackHandler> saslCallbackHandlers;
95:     private final Map<String, Long> connectionsMaxReauthMsByMechanism;
96:     private final Time time;
97:     private final LogContext logContext;
98:     private final Logger log;
99: 
100:     private SslFactory sslFactory;
101:     private Map<String, ?> configs;
102:     private KerberosShortNamer kerberosShortNamer;
103: 
104:     public SaslChannelBuilder(ConnectionMode connectionMode,
105:                               Map<String, JaasContext> jaasContexts,
106:                               SecurityProtocol securityProtocol,
107:                               ListenerName listenerName,
108:                               boolean isInterBrokerListener,
109:                               String clientSaslMechanism,
110:                               CredentialCache credentialCache,
111:                               DelegationTokenCache tokenCache,
112:                               String sslClientAuthOverride,
113:                               Time time,
114:                               LogContext logContext,
115:                               Function<Short, ApiVersionsResponse> apiVersionSupplier) {
116:         this.connectionMode = connectionMode;
117:         this.jaasContexts = jaasContexts;
118:         this.loginManagers = new HashMap<>(jaasContexts.size());
119:         this.subjects = new HashMap<>(jaasContexts.size());
120:         this.securityProtocol = securityProtocol;
121:         this.listenerName = listenerName;
122:         this.isInterBrokerListener = isInterBrokerListener;
123:         this.clientSaslMechanism = clientSaslMechanism;
124:         this.credentialCache = credentialCache;
125:         this.tokenCache = tokenCache;
126:         this.sslClientAuthOverride = sslClientAuthOverride;
127:         this.saslCallbackHandlers = new HashMap<>();
128:         this.connectionsMaxReauthMsByMechanism = new HashMap<>();
129:         this.time = time;
130:         this.logContext = logContext;
131:         this.log = logContext.logger(getClass());
132:         this.apiVersionSupplier = apiVersionSupplier;
133: 
134:         if (connectionMode == ConnectionMode.SERVER && apiVersionSupplier == null) {
135:             throw new IllegalArgumentException("Server channel builder must provide an ApiVersionResponse supplier");
136:         }
137:     }
138: 
139:     @SuppressWarnings("unchecked")
140:     @Override
141:     public void configure(Map<String, ?> configs) throws KafkaException {
142:         try {
143:             this.configs = configs;
144:             if (connectionMode == ConnectionMode.SERVER) {
145:                 createServerCallbackHandlers(configs);
146:                 createConnectionsMaxReauthMsMap(configs);
147:             } else
148:                 createClientCallbackHandler(configs);
149:             for (Map.Entry<String, AuthenticateCallbackHandler> entry : saslCallbackHandlers.entrySet()) {
150:                 String mechanism = entry.getKey();
151:                 entry.getValue().configure(configs, mechanism, jaasContexts.get(mechanism).configurationEntries());
152:             }
153: 
154:             Class<? extends Login> defaultLoginClass = defaultLoginClass();
155:             if (connectionMode == ConnectionMode.SERVER && jaasContexts.containsKey(SaslConfigs.GSSAPI_MECHANISM)) {
156:                 String defaultRealm;
157:                 try {
158:                     defaultRealm = defaultKerberosRealm();
159:                 } catch (Exception ke) {
160:                     defaultRealm = "";
161:                 }
162:                 List<String> principalToLocalRules = (List<String>) configs.get(BrokerSecurityConfigs.SASL_KERBEROS_PRINCIPAL_TO_LOCAL_RULES_CONFIG);
163:                 if (principalToLocalRules != null)
164:                     kerberosShortNamer = KerberosShortNamer.fromUnparsedRules(defaultRealm, principalToLocalRules);
165:             }
166:             for (Map.Entry<String, JaasContext> entry : jaasContexts.entrySet()) {
167:                 String mechanism = entry.getKey();
168:                 // With static JAAS configuration, use KerberosLogin if Kerberos is enabled. With dynamic JAAS configuration,
169:                 // use KerberosLogin only for the LoginContext corresponding to GSSAPI
170:                 LoginManager loginManager = LoginManager.acquireLoginManager(entry.getValue(), mechanism, defaultLoginClass, configs);
171:                 loginManagers.put(mechanism, loginManager);
172:                 Subject subject = loginManager.subject();
173:                 subjects.put(mechanism, subject);
174:                 if (connectionMode == ConnectionMode.SERVER && mechanism.equals(SaslConfigs.GSSAPI_MECHANISM))
175:                     maybeAddNativeGssapiCredentials(subject);
176:             }
177:             if (this.securityProtocol == SecurityProtocol.SASL_SSL) {
178:                 // Disable SSL client authentication as we are using SASL authentication
179:                 this.sslFactory = new SslFactory(connectionMode, sslClientAuthOverride, isInterBrokerListener);
180:                 this.sslFactory.configure(configs);
181:             }
182:         } catch (Throwable e) {
183:             close();
184:             throw new KafkaException(e);
185:         }
186:     }
187: 
188:     @Override
189:     public Set<String> reconfigurableConfigs() {
190:         return securityProtocol == SecurityProtocol.SASL_SSL ? SslConfigs.RECONFIGURABLE_CONFIGS : Collections.emptySet();
191:     }
192: 
193:     @Override
194:     public void validateReconfiguration(Map<String, ?> configs) throws ConfigException {
195:         if (this.securityProtocol == SecurityProtocol.SASL_SSL)
196:             try {
197:                 sslFactory.validateReconfiguration(configs);
198:             } catch (IllegalStateException e) {
199:                 throw new ConfigException("SASL reconfiguration failed due to " + e);
200:             }
201:     }
202: 
203:     @Override
204:     public void reconfigure(Map<String, ?> configs) {
205:         if (this.securityProtocol == SecurityProtocol.SASL_SSL)
206:             sslFactory.reconfigure(configs);
207:     }
208: 
209:     @Override
210:     public ListenerName listenerName() {
211:         return listenerName;
212:     }
213: 
214:     @Override
215:     public KafkaChannel buildChannel(String id, SelectionKey key, int maxReceiveSize,
216:                                      MemoryPool memoryPool, ChannelMetadataRegistry metadataRegistry) throws KafkaException {
217:         TransportLayer transportLayer = null;
218:         try {
219:             SocketChannel socketChannel = (SocketChannel) key.channel();
220:             Socket socket = socketChannel.socket();
221:             transportLayer = buildTransportLayer(id, key, socketChannel, metadataRegistry);
222:             final TransportLayer finalTransportLayer = transportLayer;
223:             Supplier<Authenticator> authenticatorCreator;
224:             if (connectionMode == ConnectionMode.SERVER) {
225:                 authenticatorCreator = () -> buildServerAuthenticator(configs,
226:                         Collections.unmodifiableMap(saslCallbackHandlers),
227:                         id,
228:                         finalTransportLayer,
229:                         Collections.unmodifiableMap(subjects),
230:                         Collections.unmodifiableMap(connectionsMaxReauthMsByMechanism),
231:                         metadataRegistry);
232:             } else {
233:                 LoginManager loginManager = loginManagers.get(clientSaslMechanism);
234:                 authenticatorCreator = () -> buildClientAuthenticator(configs,
235:                         saslCallbackHandlers.get(clientSaslMechanism),
236:                         id,
237:                         socket.getInetAddress().getHostName(),
238:                         loginManager.serviceName(),
239:                         finalTransportLayer,
240:                         subjects.get(clientSaslMechanism));
241:             }
242:             return new KafkaChannel(id, transportLayer, authenticatorCreator, maxReceiveSize,
243:                 memoryPool != null ? memoryPool : MemoryPool.NONE, metadataRegistry);
244:         } catch (Exception e) {
245:             // Ideally these resources are closed by the KafkaChannel but this builder should close the resources instead
246:             // if an error occurs due to which KafkaChannel is not created.
247:             Utils.closeQuietly(transportLayer, "transport layer for channel Id: " + id);
248:             throw new KafkaException(e);
249:         }
250:     }
251: 
252:     @Override
253:     public void close()  {
254:         for (LoginManager loginManager : loginManagers.values())
255:             loginManager.release();
256:         loginManagers.clear();
257:         for (AuthenticateCallbackHandler handler : saslCallbackHandlers.values())
258:             handler.close();
259:         if (sslFactory != null) sslFactory.close();
260:     }
261: 
262:     // Visible to override for testing
263:     protected TransportLayer buildTransportLayer(String id, SelectionKey key, SocketChannel socketChannel,
264:                                                  ChannelMetadataRegistry metadataRegistry) throws IOException {
265:         if (this.securityProtocol == SecurityProtocol.SASL_SSL) {
266:             return SslTransportLayer.create(id, key,
267:                 sslFactory.createSslEngine(socketChannel.socket()),
268:                 metadataRegistry);
269:         } else {
270:             return new PlaintextTransportLayer(key);
