96:     /**
97:      * The internal state transitions for initial authentication of a channel on the
98:      * server side are declared in order, starting with {@link #INITIAL_REQUEST} and
99:      * ending in either {@link #COMPLETE} or {@link #FAILED}.
100:      * <p>
101:      * Re-authentication of a channel on the server side starts with the state
102:      * {@link #REAUTH_PROCESS_HANDSHAKE}. It may then flow to
103:      * {@link #REAUTH_BAD_MECHANISM} before a transition to {@link #FAILED} if
104:      * re-authentication is attempted with a mechanism different than the original
105:      * one; otherwise it joins the authentication flow at the {@link #AUTHENTICATE}
106:      * state and likewise ends at either {@link #COMPLETE} or {@link #FAILED}.
107:      */
108:     private enum SaslState {
109:         INITIAL_REQUEST,               // May be SaslHandshake or ApiVersions for authentication
110:         HANDSHAKE_OR_VERSIONS_REQUEST, // May be SaslHandshake or ApiVersions
111:         HANDSHAKE_REQUEST,             // After an ApiVersions request, next request must be SaslHandshake
112:         AUTHENTICATE,                  // Authentication tokens (SaslHandshake v1 and above indicate SaslAuthenticate headers)
113:         COMPLETE,                      // Authentication completed successfully
114:         FAILED,                        // Authentication failed
115:         REAUTH_PROCESS_HANDSHAKE,      // Initial state for re-authentication, processes SASL handshake request
116:         REAUTH_BAD_MECHANISM,          // When re-authentication requested with wrong mechanism, generate exception
117:     }
