35: /**
36:  * Simple SaslServer implementation for SASL/PLAIN. In order to make this implementation
37:  * fully pluggable, authentication of username/password is fully contained within the
38:  * server implementation.
39:  * <p>
40:  * Valid users with passwords are specified in the Jaas configuration file. Each user
41:  * is specified with user_<username> as key and <password> as value. This is consistent
42:  * with Zookeeper Digest-MD5 implementation.
43:  * <p>
44:  * To avoid storing clear passwords on disk or to integrate with external authentication
45:  * servers in production systems, this module can be replaced with a different implementation.
46:  *
47:  */
48: public class PlainSaslServer implements SaslServer {
49: 
50:     public static final String PLAIN_MECHANISM = "PLAIN";
51: 
52:     private final CallbackHandler callbackHandler;
53:     private boolean complete;
54:     private String authorizationId;
55: 
56:     public PlainSaslServer(CallbackHandler callbackHandler) {
57:         this.callbackHandler = callbackHandler;
58:     }
59: 
60:     /**
61:      * @throws SaslAuthenticationException if username/password combination is invalid or if the requested
62:      *         authorization id is not the same as username.
63:      * <p>
64:      * <b>Note:</b> This method may throw {@link SaslAuthenticationException} to provide custom error messages
65:      * to clients. But care should be taken to avoid including any information in the exception message that
66:      * should not be leaked to unauthenticated clients. It may be safer to throw {@link SaslException} in
67:      * some cases so that a standard error message is returned to clients.
68:      * </p>
69:      */
70:     @Override
71:     public byte[] evaluateResponse(byte[] responseBytes) throws SaslAuthenticationException {
72:         /*
73:          * Message format (from https://tools.ietf.org/html/rfc4616):
74:          *
75:          * message   = [authzid] UTF8NUL authcid UTF8NUL passwd
76:          * authcid   = 1*SAFE ; MUST accept up to 255 octets
77:          * authzid   = 1*SAFE ; MUST accept up to 255 octets
78:          * passwd    = 1*SAFE ; MUST accept up to 255 octets
79:          * UTF8NUL   = %x00 ; UTF-8 encoded NUL character
80:          *
81:          * SAFE      = UTF1 / UTF2 / UTF3 / UTF4
82:          *                ;; any UTF-8 encoded Unicode character except NUL
83:          */
84: 
85:         String response = new String(responseBytes, StandardCharsets.UTF_8);
86:         List<String> tokens = extractTokens(response);
87:         String authorizationIdFromClient = tokens.get(0);
88:         String username = tokens.get(1);
89:         String password = tokens.get(2);
90: 
91:         if (username.isEmpty()) {
92:             throw new SaslAuthenticationException("Authentication failed: username not specified");
93:         }
94:         if (password.isEmpty()) {
95:             throw new SaslAuthenticationException("Authentication failed: password not specified");
96:         }
97: 
98:         NameCallback nameCallback = new NameCallback("username", username);
99:         PlainAuthenticateCallback authenticateCallback = new PlainAuthenticateCallback(password.toCharArray());
100:         try {
101:             callbackHandler.handle(new Callback[]{nameCallback, authenticateCallback});
102:         } catch (Throwable e) {
103:             throw new SaslAuthenticationException("Authentication failed: credentials for user could not be verified", e);
104:         }
105:         if (!authenticateCallback.authenticated())
106:             throw new SaslAuthenticationException("Authentication failed: Invalid username or password");
107:         if (!authorizationIdFromClient.isEmpty() && !authorizationIdFromClient.equals(username))
108:             throw new SaslAuthenticationException("Authentication failed: Client requested an authorization id that is different from username");
109: 
110:         this.authorizationId = username;
111: 
112:         complete = true;
113:         return new byte[0];
114:     }
115: 
116:     private List<String> extractTokens(String string) {
117:         List<String> tokens = new ArrayList<>();
118:         int startIndex = 0;
119:         for (int i = 0; i < 4; ++i) {
120:             int endIndex = string.indexOf("\u0000", startIndex);
121:             if (endIndex == -1) {
122:                 tokens.add(string.substring(startIndex));
123:                 break;
124:             }
125:             tokens.add(string.substring(startIndex, endIndex));
126:             startIndex = endIndex + 1;
127:         }
128: 
129:         if (tokens.size() != 3)
130:             throw new SaslAuthenticationException("Invalid SASL/PLAIN response: expected 3 tokens, got " +
131:                 tokens.size());
132: 
133:         return tokens;
134:     }
135: 
136:     @Override
137:     public String getAuthorizationID() {
138:         if (!complete)
139:             throw new IllegalStateException("Authentication exchange has not completed");
140:         return authorizationId;
141:     }
142: 
143:     @Override
144:     public String getMechanismName() {
145:         return PLAIN_MECHANISM;
146:     }
147: 
148:     @Override
149:     public Object getNegotiatedProperty(String propName) {
150:         if (!complete)
151:             throw new IllegalStateException("Authentication exchange has not completed");
152:         return null;
153:     }
154: 
155:     @Override
156:     public boolean isComplete() {
157:         return complete;
158:     }
159: 
160:     @Override
161:     public byte[] unwrap(byte[] incoming, int offset, int len) {
162:         if (!complete)
163:             throw new IllegalStateException("Authentication exchange has not completed");
164:         throw new IllegalStateException("PLAIN supports neither integrity nor privacy");
165:     }
166: 
167:     @Override
168:     public byte[] wrap(byte[] outgoing, int offset, int len) {
169:         if (!complete)
170:             throw new IllegalStateException("Authentication exchange has not completed");
171:         throw new IllegalStateException("PLAIN supports neither integrity nor privacy");
172:     }
173: 
174:     @Override
175:     public void dispose() {
176:     }
177: 
178:     public static class PlainSaslServerFactory implements SaslServerFactory {
179: 
180:         @Override
181:         public SaslServer createSaslServer(String mechanism, String protocol, String serverName, Map<String, ?> props, CallbackHandler cbh)
182:             throws SaslException {
183: 
184:             if (!PLAIN_MECHANISM.equals(mechanism))
185:                 throw new SaslException(String.format("Mechanism \'%s\' is not supported. Only PLAIN is supported.", mechanism));
186: 
187:             return new PlainSaslServer(cbh);
188:         }
189: 
190:         @Override
191:         public String[] getMechanismNames(Map<String, ?> props) {
192:             if (props == null) return new String[]{PLAIN_MECHANISM};
193:             String noPlainText = (String) props.get(Sasl.POLICY_NOPLAINTEXT);
194:             if ("true".equals(noPlainText))
195:                 return new String[]{};
196:             else
197:                 return new String[]{PLAIN_MECHANISM};
198:         }
199:     }
200: }
